def dispatch_json_path(self, key_string: str) -> Optional[BaseGrammarObject]:
    """Dispatch a JSON path constraint.

    Converts the JSONPath expression *key_string* into a JSON Schema that
    enforces the structural requirements implied by the path, then
    delegates to :meth:`dispatch_json`.  This means every grammar backend
    (xgrammar, outlines, llguidance, …) automatically gains JSON path
    support without any backend-specific changes.

    Args:
        key_string: A JSONPath expression, e.g. ``"$.store.book[*].author"``.

    Returns:
        A :class:`BaseGrammarObject` that constrains generation to JSON
        matching the schema derived from *key_string*, or
        :data:`INVALID_GRAMMAR_OBJ` if the path is invalid.
    """
    from sglang.srt.constrained.json_path_constraint import json_path_to_schema

    try:
        schema = json_path_to_schema(key_string)
    except ValueError as exc:
        logger.error(f"Invalid json_path constraint: {key_string=}, {exc=}")
        return INVALID_GRAMMAR_OBJ
    return self.dispatch_json(schema)

